{
  "executive_summary": "A lightweight ML serving architecture for real-time delivery time prediction, optimized for a small team of 4. The design separates the hot path (feature assembly + model inference at <100ms P99) from the cold path (weekly batch retraining pipeline). Model versioning with instant rollback is achieved via a model registry with blue-green serving slots. The architecture avoids heavyweight MLOps platforms in favor of simple, proven components the team can own end-to-end.",

  "architecture": {
    "components": [
      {
        "name": "Prediction Service",
        "responsibility": "Accepts prediction requests, assembles features, runs model inference, returns estimated delivery time. Stateless, horizontally scalable. Loads model artifact from local disk (pulled from registry on deploy/rollback).",
        "boundaries": "Owns the hot path only. No training logic. No direct DB writes. Reads from Feature Store (cache) and holds a pinned model version in-process."
      },
      {
        "name": "Feature Store (Online)",
        "responsibility": "Serves precomputed and real-time features with sub-10ms latency. Stores courier load snapshots, zone-level historical stats, weather cache. Redis or DynamoDB single-table.",
        "boundaries": "Read-heavy, written to by the Feature Pipeline. The Prediction Service is its only consumer on the hot path."
      },
      {
        "name": "Feature Pipeline",
        "responsibility": "Batch and streaming jobs that compute features from raw event data (deliveries, GPS pings, weather API) and materialize them into the online Feature Store and the offline training dataset (Parquet in S3).",
        "boundaries": "Owns the ETL/ELT logic. Does not serve real-time traffic. Runs on a schedule (hourly for streaming features, daily for batch aggregates)."
      },
      {
        "name": "Training Pipeline",
        "responsibility": "Weekly batch job: reads offline feature dataset, trains model (gradient-boosted trees via XGBoost/LightGBM), evaluates against holdout set, registers new model artifact with metrics in the Model Registry. Triggers validation gate.",
        "boundaries": "Runs in an isolated compute environment (e.g., SageMaker Training Job or a dedicated k8s job). No access to production serving infrastructure directly."
      },
      {
        "name": "Model Registry",
        "responsibility": "Versioned store of model artifacts with metadata (training date, metrics, dataset hash, status: staging/production/archived). Supports promoting and rolling back model versions atomically.",
        "boundaries": "Simple metadata DB (Postgres table) + S3 for artifact blobs. Source of truth for which model version is 'production'. Not in the hot path — the Prediction Service pulls artifacts on promotion events."
      },
      {
        "name": "Validation Gate",
        "responsibility": "Automated quality check after training: compares new model metrics (MAE, P90 error, latency benchmark) against the current production model. Auto-promotes if metrics improve; blocks and alerts if they degrade.",
        "boundaries": "Runs as a step in the Training Pipeline. Can be overridden manually by an ML engineer for force-promotion or rollback."
      },
      {
        "name": "Monitoring & Observability",
        "responsibility": "Tracks prediction latency (P50/P95/P99), prediction drift (actual vs predicted delivery times logged asynchronously), feature freshness, model version in use, error rates.",
        "boundaries": "Consumes async logs/metrics from the Prediction Service and delivery outcome events. Does not sit in the hot path."
      }
    ],
    "interfaces": [
      {
        "from": "Checkout Service",
        "to": "Prediction Service",
        "contract": "POST /predict — Request: {order_weight, distance_km, zone_id, time_of_day, weather_code} → Response: {estimated_minutes, confidence_interval, model_version} — P99 < 100ms",
        "coupling_type": "synchronous, runtime dependency (hot path)"
      },
      {
        "from": "Prediction Service",
        "to": "Feature Store (Online)",
        "contract": "GET features by (zone_id, courier_pool_id, time_bucket) — returns precomputed features: avg_courier_load, zone_congestion_score, historical_delivery_p50",
        "coupling_type": "synchronous, runtime dependency — cache miss must not blow latency budget"
      },
      {
        "from": "Feature Pipeline",
        "to": "Feature Store (Online)",
        "contract": "UPSERT computed features keyed by dimension (zone, time_bucket, courier_pool). Eventual consistency acceptable (features lag reality by minutes).",
        "coupling_type": "asynchronous, write-only"
      },
      {
        "from": "Feature Pipeline",
        "to": "Offline Feature Dataset (S3)",
        "contract": "Writes Parquet files partitioned by date. Schema: all feature columns + actual_delivery_minutes label.",
        "coupling_type": "asynchronous, batch"
      },
      {
        "from": "Training Pipeline",
        "to": "Model Registry",
        "contract": "Registers model artifact (serialized model binary + metadata JSON) under a new version. Sets status=staging.",
        "coupling_type": "asynchronous, event-driven (triggers Validation Gate)"
      },
      {
        "from": "Validation Gate",
        "to": "Model Registry",
        "contract": "Promotes model version to status=production OR rejects. On promotion, publishes a ModelPromoted event.",
        "coupling_type": "asynchronous, event-driven"
      },
      {
        "from": "Model Registry",
        "to": "Prediction Service",
        "contract": "ModelPromoted event → Prediction Service pulls new artifact from S3, loads into memory, swaps atomically (blue-green in-process). Rollback = re-promote previous version.",
        "coupling_type": "asynchronous, event-driven — no downtime on swap"
      },
      {
        "from": "Prediction Service",
        "to": "Monitoring & Observability",
        "contract": "Emits async structured logs: {request_id, features_used, prediction, model_version, latency_ms}. Delivery outcome joined later for drift detection.",
        "coupling_type": "asynchronous, fire-and-forget"
      }
    ],
    "data_flow": "HOT PATH (checkout): Checkout Service → Prediction Service → (1) assembles request features from payload, (2) enriches with precomputed features from Feature Store (Online) in <10ms, (3) runs in-process model inference in <5ms for tree-based model, (4) returns prediction. Total budget: <100ms P99 with network overhead. COLD PATH (training): Raw events → Feature Pipeline → Offline Dataset (S3 Parquet) → Training Pipeline → Model artifact → Model Registry → Validation Gate → (if pass) promote → Prediction Service hot-reloads new model. FEEDBACK LOOP: Actual delivery times are logged, joined with predictions in the Monitoring system, fed back into the next training cycle's label data.",
    "patterns_used": [
      {
        "pattern": "Blue-Green Model Serving",
        "rationale": "The Prediction Service holds two model slots in memory. On promotion, the new model is loaded into the standby slot, then an atomic pointer swap routes traffic. Rollback is the reverse swap — instant, zero-downtime. This satisfies the rollback requirement without infrastructure complexity."
      },
      {
        "pattern": "Feature Store (Online/Offline split)",
        "rationale": "Separates the latency-sensitive online feature lookup (Redis, <10ms) from the batch-oriented offline feature dataset (S3 Parquet for training). Prevents training concerns from polluting the hot path. Standard ML platform pattern even at small scale."
      },
      {
        "pattern": "Validation Gate (Automated Quality Gate)",
        "rationale": "Prevents model regressions from reaching production. Compares new model against incumbent on holdout metrics. Auto-promotes or blocks. Critical for a team of 4 — reduces manual review burden while maintaining safety."
      },
      {
        "pattern": "In-Process Model Inference (no model server)",
        "rationale": "For tree-based models (XGBoost/LightGBM), inference is <5ms in-process. A separate model server (TF Serving, Triton) adds network hop latency (~10-30ms) and operational complexity. With 4 engineers, eliminating an entire service from the hot path is a significant win. If the team later moves to deep learning models, this is the point to introduce a model server."
      },
      {
        "pattern": "Event-Driven Model Deployment",
        "rationale": "Model Registry publishes promotion events rather than requiring the Prediction Service to poll. Decouples the training cycle from serving. Prediction Service instances subscribe and self-update."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Prediction Serving",
        "classification": "core",
        "aggregates": ["PredictionRequest (value object: features + result)", "ServingModel (entity: loaded model artifact with version, metrics, status)"]
      },
      {
        "name": "Feature Engineering",
        "classification": "supporting",
        "aggregates": ["FeatureSet (entity: versioned feature schema + materialized values)", "FeatureSource (entity: raw event stream or batch source)"]
      },
      {
        "name": "Model Lifecycle",
        "classification": "core",
        "aggregates": ["ModelVersion (aggregate root: version, artifact URI, metrics, status [staging/production/archived], training dataset hash)", "TrainingRun (entity: hyperparams, duration, evaluation results)"]
      },
      {
        "name": "Delivery Operations",
        "classification": "generic",
        "aggregates": ["Upstream context owned by the logistics platform — provides order details, courier assignments, delivery outcomes. We are a consumer."]
      }
    ],
    "context_map": [
      {
        "upstream": "Delivery Operations",
        "downstream": "Feature Engineering",
        "relationship": "Conformist — we consume their event schema for delivery events, GPS pings, and order data as-is. Not worth building an ACL for a team of 4 unless their schema is unstable."
      },
      {
        "upstream": "Feature Engineering",
        "downstream": "Prediction Serving",
        "relationship": "Customer-Supplier — Feature Engineering materializes features to the online store in a schema that Prediction Serving dictates. Serving team defines what features it needs."
      },
      {
        "upstream": "Model Lifecycle",
        "downstream": "Prediction Serving",
        "relationship": "Customer-Supplier — Model Lifecycle produces and validates artifacts; Prediction Serving consumes them. Serving dictates the artifact format (serialized model binary + metadata)."
      },
      {
        "upstream": "Feature Engineering",
        "downstream": "Model Lifecycle",
        "relationship": "Shared Kernel — both contexts share the feature schema definition. Changes require coordination. Acceptable given the team size (same 2 ML engineers own both)."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "In-process inference (XGBoost/LightGBM) instead of a model server (TF Serving, Triton, Seldon)",
      "gains": "Eliminates a network hop (~10-30ms saved), removes an entire service to operate, trivially meets 100ms P99, simple deployment model",
      "sacrifices": "Locks model type to tree-based models. Cannot easily serve deep learning models. Model size limited by service memory. No GPU inference.",
      "alternatives_considered": ["TF Serving sidecar — adds latency and operational burden for a tree model that doesn't need it", "Triton Inference Server — overkill for single model, team of 4 cannot justify operational cost", "ONNX Runtime — viable middle ground if model type diversifies later"]
    },
    {
      "decision": "Redis for online Feature Store instead of a managed feature store (Feast, Tecton, SageMaker Feature Store)",
      "gains": "Sub-millisecond latency, team already likely knows Redis, no vendor lock-in, simple to operate at this scale",
      "sacrifices": "No built-in feature versioning, lineage, or point-in-time-correct joins for training. Team must build simple TTL/versioning logic.",
      "alternatives_considered": ["Feast — adds operational complexity (Feast infra) for features that a Redis hash handles fine", "DynamoDB — viable alternative if team is AWS-native, slightly higher latency but fully managed"]
    },
    {
      "decision": "Weekly batch retraining instead of continuous/online learning",
      "gains": "Simple pipeline, deterministic, auditable, easy to validate and roll back. Appropriate for delivery time prediction where patterns shift slowly.",
      "sacrifices": "Model cannot adapt to sudden distribution shifts (e.g., major weather event mid-week) until next retrain cycle.",
      "alternatives_considered": ["Daily retraining — more responsive but doubles pipeline compute cost and operational overhead for marginal gain", "Online learning — complex, harder to validate, risky for a team of 4"]
    },
    {
      "decision": "Automated Validation Gate instead of manual ML engineer review for every model",
      "gains": "Reduces toil for 2 ML engineers. Enables weekly cadence without blocking on human review. Catches regressions automatically.",
      "sacrifices": "Risk of promoting a model that passes metrics but has subtle issues (e.g., biased predictions for a specific zone). Mitigated by monitoring + easy rollback.",
      "alternatives_considered": ["Full manual review — doesn't scale with weekly cadence and 2 ML engineers", "Shadow mode deployment — ideal but adds infrastructure complexity the team may not have bandwidth for initially"]
    }
  ],

  "flexibility_points": [
    {
      "area": "Model algorithm",
      "evolution_path": "Starting with XGBoost/LightGBM for speed and interpretability. If prediction quality plateaus, the in-process inference can be swapped to ONNX Runtime to support neural network models without introducing a model server. The Model Registry already versions artifacts agnostically."
    },
    {
      "area": "Feature sources",
      "evolution_path": "Feature Pipeline is designed to add new feature sources (traffic API, holiday calendar, promotional events) without modifying the Prediction Service. New features are materialized to the Feature Store; the model is retrained to use them."
    },
    {
      "area": "Retraining frequency",
      "evolution_path": "The Training Pipeline is a scheduled job. Changing from weekly to daily is a config change, not an architecture change. The Validation Gate and Model Registry handle any cadence."
    },
    {
      "area": "Model serving topology",
      "evolution_path": "If latency budget loosens or model complexity increases (deep learning), the in-process inference can be extracted to a dedicated model server behind a gRPC interface. The Prediction Service becomes a thin orchestrator."
    }
  ],

  "rigidity_points": [
    {
      "area": "100ms P99 latency budget",
      "reason": "This hard constraint drives the entire hot-path architecture: in-process inference, Redis feature store, no model server. Relaxing this constraint would open up more model types and serving options. Tightening it further would require edge caching or precomputation."
    },
    {
      "area": "Synchronous prediction in checkout flow",
      "reason": "The prediction is on the critical checkout path. It cannot be made async or eventual. This means the Prediction Service must be highly available and the Feature Store must have a cache-hit strategy that doesn't degrade under load."
    },
    {
      "area": "Feature schema shared between training and serving",
      "reason": "Training-serving skew is the #1 ML production bug. The feature schema used at training time MUST match serving time exactly. This coupling is intentional and must be enforced via a shared schema definition (e.g., a protobuf or JSON schema) versioned alongside the model."
    }
  ],

  "risks": [
    {
      "risk": "Training-serving skew: features computed differently in the offline pipeline vs online Feature Store, leading to silent prediction degradation",
      "severity": "critical",
      "mitigation": "Share feature computation logic between online and offline paths (same Python functions or a shared library). Add a CI check that computes features both ways on a sample dataset and asserts equivalence. Monitor prediction distribution drift."
    },
    {
      "risk": "Feature Store (Redis) unavailability causes prediction failures on the checkout hot path",
      "severity": "high",
      "mitigation": "Implement a fallback strategy: if Redis is unreachable, use a stale local cache of zone-level features (refreshed every N minutes) and log degraded predictions. Set aggressive Redis timeouts (5ms) so failures are fast. Consider Redis Sentinel or Cluster for HA."
    },
    {
      "risk": "Validation Gate passes a model that performs well on metrics but poorly on a specific segment (e.g., long-distance deliveries)",
      "severity": "high",
      "mitigation": "Evaluate metrics per segment (zone, distance bucket, time of day) in the Validation Gate, not just aggregate MAE. Set per-segment regression thresholds. Add post-deployment monitoring that compares predicted vs actual by segment."
    },
    {
      "risk": "Model rollback is needed but the previous model version's features are no longer available in the Feature Store (schema changed)",
      "severity": "medium",
      "mitigation": "Pin feature schema version to model version. The Model Registry stores the feature schema hash alongside the model artifact. Rollback checks feature compatibility. Rule: never remove a feature from the online store until no production or rollback-candidate model uses it."
    },
    {
      "risk": "Team of 4 is spread too thin across serving, feature engineering, training pipeline, and monitoring",
      "severity": "medium",
      "mitigation": "Ownership split: 2 ML engineers own Training Pipeline + Feature Pipeline + Model Registry. 2 platform engineers own Prediction Service + Feature Store (Online) + Monitoring. Shared on-call. Use managed services (S3, Redis, scheduled jobs) aggressively to reduce operational surface."
    },
    {
      "risk": "Cold start latency: Prediction Service instance loads model into memory on startup, causing slow first requests",
      "severity": "low",
      "mitigation": "Preload model during startup before accepting traffic (readiness probe). Keep model artifacts small (tree models are typically <100MB). Cache model artifact locally to avoid S3 download on every restart."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Phase 1 (Weeks 1-3): Build the hot path first — Prediction Service with hardcoded/simple features and a baseline model (e.g., linear regression or a single XGBoost model trained offline). Get the /predict endpoint serving in production behind the checkout flow with latency monitoring. This proves the integration and latency budget. Phase 2 (Weeks 4-6): Build the Feature Pipeline and online Feature Store. Materialize real features into Redis. Retrain the model on real features, deploy manually via the Model Registry (Postgres table + S3). Phase 3 (Weeks 7-9): Automate the Training Pipeline (weekly cron job), Validation Gate, and event-driven model promotion. Add monitoring dashboards for prediction accuracy and drift. Phase 4 (Ongoing): Iterate on features, model complexity, and monitoring coverage.",
    "files_to_create_or_modify": [
      "services/prediction-service/ — Python (FastAPI) service: /predict endpoint, feature assembly, in-process model inference, model hot-reload",
      "services/prediction-service/model_loader.py — Blue-green model loading: two slots, atomic swap, rollback support",
      "services/prediction-service/feature_client.py — Redis client for online feature retrieval with timeout and fallback",
      "pipelines/feature-pipeline/ — Airflow DAG or simple Python scripts for batch/streaming feature computation",
      "pipelines/training-pipeline/ — Weekly training job: data loading, model training, evaluation, registry upload",
      "pipelines/training-pipeline/validation_gate.py — Automated quality check: metric comparison, per-segment evaluation, promotion/rejection",
      "infrastructure/model-registry/ — DB migration for model_versions table (version, artifact_uri, metrics_json, status, feature_schema_hash, created_at)",
      "shared/feature_schema.py — Shared feature definitions used by both online serving and offline training to prevent skew",
      "monitoring/dashboards/ — Grafana dashboard definitions for latency, prediction accuracy, drift, feature freshness"
    ],
    "patterns_to_follow": "Use FastAPI for the Prediction Service (async, fast, good for ML serving). Load model via joblib/pickle for XGBoost — keep it in-process, no model server. Use Redis HGETALL for feature retrieval with a 5ms timeout. Implement health checks (liveness: process alive, readiness: model loaded). Use structured logging (JSON) for all prediction requests to enable downstream accuracy analysis. Use Airflow or a simple cron + Python for the training pipeline — avoid Kubeflow/MLflow unless the team grows.",
    "pitfalls_to_avoid": [
      "Do NOT introduce a separate model serving infrastructure (TF Serving, Seldon, KServe) for tree-based models — it adds latency and ops burden with no benefit at this scale",
      "Do NOT compute features in the Prediction Service at request time from raw data — precompute everything in the Feature Pipeline, serve from cache",
      "Do NOT share a database between the Prediction Service and the Training Pipeline — they have different access patterns and availability requirements",
      "Do NOT skip the Validation Gate even for urgent model updates — a bad model on the checkout path directly impacts revenue",
      "Do NOT use a heavyweight ML platform (SageMaker Pipelines, Vertex AI Pipelines) for a team of 4 — the operational overhead will consume the entire team's bandwidth",
      "Do NOT log prediction requests synchronously to a database — use async structured logs to avoid adding latency to the hot path"
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 85,
    "high_confidence_areas": [
      "Hot path architecture: in-process inference + Redis feature store is well-proven for tree models under 100ms P99",
      "Blue-green model serving for instant rollback — standard pattern, low implementation risk",
      "Team split: ML engineers on pipelines, platform engineers on serving — natural ownership boundaries",
      "Phased delivery approach: hot path first, then features, then automation"
    ],
    "low_confidence_areas": [
      "Feature Store technology choice (Redis vs DynamoDB) depends on team's existing infrastructure and AWS/cloud preferences — both are viable",
      "Exact feature set and model complexity are unknown — architecture assumes tree-based models remain sufficient, which depends on prediction accuracy requirements",
      "Monitoring and drift detection depth depends on how quickly delivery patterns shift — may need more investment if seasonal/weather patterns cause frequent drift"
    ],
    "assumptions": [
      "Tree-based models (XGBoost/LightGBM) provide sufficient prediction accuracy for delivery time estimation — validated by industry precedent",
      "The team has access to standard cloud infrastructure (object storage, managed Redis, container orchestration)",
      "Delivery volume is moderate (not millions of concurrent checkout requests) — if extreme scale, would need to revisit with caching/precomputation strategies",
      "The existing logistics platform can emit delivery events and outcomes for training data collection"
    ]
  }
}

